+fn next_quarantine_version(state: &FleetSharedState, zone_id: &str) -> u64 {
+    state
+        .actions
+        .iter()
+        .filter_map(|record| match &record.action {
+            PersistedFleetAction::Quarantine {
+                zone_id: action_zone,
+                quarantine_version,
+                ..
+            } if action_zone == zone_id => Some(*quarantine_version),
+            _ => None,
+        })
+        .max()
+        .unwrap_or(0)
+        .saturating_add(1)
+}
