+fn append_trust_quarantine_action(
+    project_root: &Path,
+    artifact: &str,
+    affected_cards: usize,
+) -> Result<String> {
+    let loaded = load_fleet_state(project_root)?;
+    let mut transport = FileFleetTransport::new(loaded.state_dir.clone());
+    transport
+        .initialize()
+        .map_err(|err| anyhow::anyhow!(err.to_string()))?;
