+fn known_runtime_compatibility_issues(
+    runtime: &str,
+    major_version: Option<u64>,
+    engine_requirement: Option<&str>,
+    engine_requirement_satisfied: Option<bool>,
+) -> Vec<String> {
+    let mut issues = Vec::new();
